// Goal: prove (optional_value_view(ov) == optional_value_view(r1) &&
    //             optional_value_view(ov) == optional_value_view(r2))
    //        ==> ((r1 is Some) == (r2 is Some)) && ((r1 is Some) ==> r1->Some_0 == r2->Some_0)
    // The first conjunct follows from optional_value_view definition.
    // The second conjunct requires Vec<u8> equality, which in Verus spec is NOT determined
    // by view equality (Vec is external_body). Hence this synthetic determinism check is
    // unprovable from the underspecified `optional_value_view` precondition.
    broadcast use vstd::std_specs::vec::group_vec_axioms;
    assert((optional_value_view(ov) is Some) == (ov is Some));
    assert((optional_value_view(r1) is Some) == (r1 is Some));
    assert((optional_value_view(r2) is Some) == (r2 is Some));
    if ov is Some && r1 is Some && r2 is Some
        && optional_value_view(ov) == optional_value_view(r1)
        && optional_value_view(ov) == optional_value_view(r2)
    {
        assert(optional_value_view(ov)->Some_0 == ov->Some_0@);
        assert(optional_value_view(r1)->Some_0 == r1->Some_0@);
        assert(optional_value_view(r2)->Some_0 == r2->Some_0@);
        assert(r1->Some_0@ == r2->Some_0@);
    }
